/* Generated by Trae Work */
/* Google Gemini AI 图片识别 — 精准提取电费电量数据 */
(function () {
  'use strict';

  window.GeminiOCR = {
    _key: '',
    _model: 'gemini-2.0-flash',

    setKey: function (key) {
      this._key = key.trim();
      try { localStorage.setItem('gemini_key', this._key); } catch (e) {}
    },

    getKey: function () {
      if (this._key) return this._key;
      try { this._key = localStorage.getItem('gemini_key') || ''; } catch (e) {}
      return this._key;
    },

    _fileToBase64: function (file) {
      return new Promise(function (resolve, reject) {
        var reader = new FileReader();
        reader.onload = function () {
          var base64 = reader.result.split(',')[1];
          resolve(base64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
      });
    },

    _getMimeType: function (file) {
      return file.type || 'image/png';
    },

    recognize: async function (imageFile, type, onProgress) {
      var key = this.getKey();
      if (!key) throw new Error('请先输入 Gemini API Key');

      if (onProgress) onProgress('正在准备图片...');

      var base64 = await this._fileToBase64(imageFile);
      var mimeType = this._getMimeType(imageFile);
      var prompt = type === 'monthly' ? this._monthlyPrompt() : this._dailyPrompt();

      if (onProgress) onProgress('正在调用 AI 识别（约3-5秒）...');

      var url = 'https://generativelanguage.googleapis.com/v1beta/models/' + this._model + ':generateContent?key=' + key;

      var res = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ parts: [{ text: prompt }, { inline_data: { mime_type: mimeType, data: base64 } }] }],
          generationConfig: { temperature: 0.1, maxOutputTokens: 4096 }
        })
      });

      if (!res.ok) {
        var errData = {};
        try { errData = await res.json(); } catch (e) {}
        throw new Error((errData.error && errData.error.message) || ('HTTP ' + res.status));
      }

      var data = await res.json();
      var text = (data.candidates && data.candidates[0] && data.candidates[0].content && data.candidates[0].content.parts[0])
        ? data.candidates[0].content.parts[0].text : '';

      if (!text) throw new Error('AI 未返回内容');

      if (onProgress) onProgress('正在解析结果...');

      return this._parseResponse(text, type);
    },

    _monthlyPrompt: function () {
      return '你是一个精准的数据提取助手。请从这张电费账单截图中提取月度用电数据。

' +
        '要求：
' +
        '1. 每行一条，格式: 月份 电量 电费
' +
        '2. 月份格式: 用数字表示，如 1, 2, ..., 12
' +
        '3. 电量单位: kWh，只写数字，不写单位
' +
        '4. 电费单位: 元，只写数字，不写单位
' +
        '5. 只提取当月数据，不要年累计数据
' +
        '6. 不要输出任何其他文字，只输出数据行
' +
        '7. 如果截图包含年份信息，在最前面加一行: YEAR:XXXX
' +
        '
' +
        '示例输出：
' +
        'YEAR:2026
' +
        '1 1011 543
' +
        '2 614 321
' +
        '3 263 139';
    },

    _dailyPrompt: function () {
      return '你是一个精准的数据提取助手。请从这张每日用电量截图中提取数据。
' +
        '这可能是日历视图或列表视图的截图。
' +
        '
' +
        '要求：
' +
        '1. 每行一条，格式: 日期 电量
' +
        '2. 日期格式: MM-DD，如 07-01, 07-02
' +
        '3. 电量单位: kWh，只写数字，保留两位小数
' +
        '4. 只提取每日用电数据，不要合计/日均/总计等统计值
' +
        '5. 不要输出任何其他文字，只输出数据行
' +
        '6. 如果能识别年份，在最前面加一行: YEAR:XXXX
' +
        '7. 日历网格中每个格子里有日期和对应的用电量数字，请仔细识别每个格子
' +
        '
' +
        '示例输出：
' +
        'YEAR:2026
' +
        '07-01 13.91
' +
        '07-02 11.34
' +
        '07-03 5.21';
    },

    _parseResponse: function (text, type) {
      var lines = text.split('\n').map(function (l) { return l.trim(); }).filter(function (l) { return l; });
      var year = null;
      var results = [];

      lines.forEach(function (line) {
        // 提取年份
        var ym = line.match(/^YEAR[:\s]*(\d{4})/i);
        if (ym) { year = parseInt(ym[1]); return; }

        // 月度: "1 1011 543"
        if (type === 'monthly') {
          var parts = line.split(/[\s\t]+/);
          if (parts.length >= 3) {
            var m = parseInt(parts[0]);
            var k = parseFloat(parts[1]);
            var c = parseFloat(parts[2]);
            if (m >= 1 && m <= 12 && k > 0 && c > 0) {
              results.push({ year: year || new Date().getFullYear(), month: m, kwh: k, cost: c });
            }
          }
        }

        // 每日: "07-01 13.91"
        if (type === 'daily') {
          var dm = line.match(/(\d{1,2})-(\d{1,2})[\s\t]+(\d+(?:\.\d+)?)/);
          if (dm) {
            var mo = parseInt(dm[1]);
            var d = parseInt(dm[2]);
            var kwh = parseFloat(dm[3]);
            if (mo >= 1 && mo <= 12 && d >= 1 && d <= 31 && kwh > 0 && kwh < 500) {
              var y = year || new Date().getFullYear();
              results.push({
                date: y + '-' + String(mo).padStart(2, '0') + '-' + String(d).padStart(2, '0'),
                kwh: kwh
              });
            }
          }
        }
      });

      // 去重
      var seen = {};
      results = results.filter(function (r) {
        var key = type === 'monthly' ? (r.year + '-' + r.month) : r.date;
        if (seen[key]) return false;
        seen[key] = true;
        return true;
      });

      // 排序
      results.sort(function (a, b) {
        if (type === 'monthly') return (a.year * 12 + a.month) - (b.year * 12 + b.month);
        return a.date < b.date ? -1 : 1;
      });

      return results;
    }
  };
})();
